+
+/** Retry a task-producing function up to `n` additional times after rejection. */
+export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
+  return new Task((resolve, reject) => {
+    let remaining = Math.max(0, Math.floor(n));
+    const attempt = () => {
+      let current: Task<T, E>;
+      try {
+        current = fn();
+      } catch (error) {
+        if (remaining-- > 0) attempt();
+        else reject(error as E);
+        return;
+      }
+      current.match({
+        Resolved: resolve,
+        Rejected: (reason) => {
+          if (remaining-- > 0) attempt();
+          else reject(reason);
+        },
+      });
+    };
+    attempt();
+  });
