+): Result<U[], E>;
+export function traverseMaybeAsResult<T, U extends {}, E>(
+  errValue: E
+): (items: Iterable<T>, fn: (item: T) => Maybe<U>) => Result<U[], E>;
+export function traverseMaybeAsResult<T, U extends {}, E>(
+  errValue: E, items?: Iterable<T>, maybeFn?: (item: T) => Maybe<U>
+): Result<U[], E> | ((items: Iterable<T>, fn: (item: T) => Maybe<U>) => Result<U[], E>) {
+  const op = (input: Iterable<T>, fn: (item: T) => Maybe<U>) => {
+    const values: U[] = [];
+    for (const item of input) {
+      const maybe = fn(item);
+      if (maybe.isNothing) return Result.err<U[], E>(errValue);
+      values.push(maybe.value);
+    }
+    return Result.ok<U[], E>(values);
+  };
+  return items === undefined || maybeFn === undefined ? op : op(items, maybeFn);
+}
+
+/** Zip `Maybe`s as a `Result`, converting `Nothing` to the supplied error. */
+export function zipMaybeAsResult<A extends {}, B extends {}, E>(
+  errValue: E, a: Maybe<A>, b: Maybe<B>
+): Result<[A, B], E>;
+export function zipMaybeAsResult<A extends {}, B extends {}, E>(
+  errValue: E
+): (a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>;
+export function zipMaybeAsResult<A extends {}, B extends {}, E>(
+  errValue: E, a?: Maybe<A>, b?: Maybe<B>
+): Result<[A, B], E> | ((a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>) {
+  const op = (left: Maybe<A>, right: Maybe<B>) =>
